// Direct field equalities: post1.X =~= pre.X =~= post2.X (transitively).
assert(post1_self_.kernel_entries =~= post2_self_.kernel_entries);
assert(post1_self_.kernel_entries_ghost =~= post2_self_.kernel_entries_ghost);
assert(post1_self_.page_tables =~= post2_self_.page_tables);
assert(post1_self_.page_table_pages =~= post2_self_.page_table_pages);
assert(post1_self_.free_ioids =~= post2_self_.free_ioids);
assert(post1_self_.iommu_tables =~= post2_self_.iommu_tables);
assert(post1_self_.iommu_table_pages =~= post2_self_.iommu_table_pages);
assert(post1_self_.root_table =~= post2_self_.root_table);
assert(post1_self_.root_table_cache =~= post2_self_.root_table_cache);
assert(post1_self_.pci_bitmap =~= post2_self_.pci_bitmap);
assert(post1_self_.page_table_pages@.dom() =~= post2_self_.page_table_pages@.dom());

// pcid_active agrees on all p: case-split on p == pcid.
assert forall|p: Pcid|
    post1_self_.pcid_active(p) == post2_self_.pcid_active(p) by {
    if p == pcid {
        assert(post1_self_.pcid_active(pcid) == false);
        assert(post2_self_.pcid_active(pcid) == false);
    } else {
        assert(post1_self_.pcid_active(p) == pre_self_.pcid_active(p));
        assert(post2_self_.pcid_active(p) == pre_self_.pcid_active(p));
    }
}

// ioid_active fully preserved by both runs.
assert forall|i: IOid|
    post1_self_.ioid_active(i) == post2_self_.ioid_active(i) by {
    assert(post1_self_.ioid_active(i) == pre_self_.ioid_active(i));
    assert(post2_self_.ioid_active(i) == pre_self_.ioid_active(i));
}

// pcid_to_proc_ptr agrees whenever post1.pcid_active(p): then p != pcid and both = pre.
assert forall|p: Pcid|
    post1_self_.pcid_active(p) ==>
    post1_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p) by {
    if post1_self_.pcid_active(p) {
        assert(post1_self_.pcid_active(pcid) == false);
        assert(p != pcid);
        assert(post1_self_.pcid_active(p) == pre_self_.pcid_active(p));
        assert(pre_self_.pcid_active(p));
        assert(post2_self_.pcid_active(p) == pre_self_.pcid_active(p));
        assert(post2_self_.pcid_active(p));
        assert(pre_self_.pcid_to_proc_ptr(p) == post1_self_.pcid_to_proc_ptr(p));
        assert(pre_self_.pcid_to_proc_ptr(p) == post2_self_.pcid_to_proc_ptr(p));
    }
}

// get_pagetable_mapping_by_pcid agrees on every active pcid.
assert forall|p: Pcid|
    post1_self_.pcid_active(p) ==>
    post1_self_.get_pagetable_mapping_by_pcid(p) == post2_self_.get_pagetable_mapping_by_pcid(p) by {
    if post1_self_.pcid_active(p) {
        assert(post1_self_.pcid_active(pcid) == false);
        assert(p != pcid);
        assert(post1_self_.pcid_active(p) == pre_self_.pcid_active(p));
        assert(pre_self_.pcid_active(p));
        assert(post2_self_.pcid_active(p) == pre_self_.pcid_active(p));
        assert(post2_self_.pcid_active(p));
        assert(pre_self_.get_pagetable_mapping_by_pcid(p)
            == post1_self_.get_pagetable_mapping_by_pcid(p));
        assert(pre_self_.get_pagetable_mapping_by_pcid(p)
            == post2_self_.get_pagetable_mapping_by_pcid(p));
    }
}

// ioid_to_proc_ptr agrees on every active ioid.
assert forall|i: IOid|
    post1_self_.ioid_active(i) ==>
    post1_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i) by {
    if post1_self_.ioid_active(i) {
        assert(post1_self_.ioid_active(i) == pre_self_.ioid_active(i));
        assert(pre_self_.ioid_active(i));
        assert(post2_self_.ioid_active(i) == pre_self_.ioid_active(i));
        assert(post2_self_.ioid_active(i));
        assert(pre_self_.ioid_to_proc_ptr(i) == post1_self_.ioid_to_proc_ptr(i));
        assert(pre_self_.ioid_to_proc_ptr(i) == post2_self_.ioid_to_proc_ptr(i));
    }
}

// get_iommu_table_mapping_by_ioid agrees on every active ioid.
assert forall|i: IOid|
    post1_self_.ioid_active(i) ==>
    post1_self_.get_iommu_table_mapping_by_ioid(i)
        == post2_self_.get_iommu_table_mapping_by_ioid(i) by {
    if post1_self_.ioid_active(i) {
        assert(post1_self_.ioid_active(i) == pre_self_.ioid_active(i));
        assert(pre_self_.ioid_active(i));
        assert(post2_self_.ioid_active(i) == pre_self_.ioid_active(i));
        assert(post2_self_.ioid_active(i));
        assert(pre_self_.get_iommu_table_mapping_by_ioid(i)
            == post1_self_.get_iommu_table_mapping_by_ioid(i));
        assert(pre_self_.get_iommu_table_mapping_by_ioid(i)
            == post2_self_.get_iommu_table_mapping_by_ioid(i));
    }
}

// Both runs deactivate pcid identically.
assert(post1_self_.pcid_active(pcid) == false);
assert(post2_self_.pcid_active(pcid) == false);
